<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();if(vp3_method()==='POST'){vp3_verify_csrf();$id=(int)vp3_input('id');if($id>0)vp3_db()->prepare("UPDATE notifications SET status='read',read_at=NOW() WHERE id=? AND recipient_type='customer' AND recipient_id=?")->execute([$id,$customer['id']]);else vp3_db()->prepare("UPDATE notifications SET status='read',read_at=NOW() WHERE recipient_type='customer' AND recipient_id=? AND status='unread'")->execute([$customer['id']]);vp3_redirect('account-notifications.php');}$rows=[];$ready=false;if(vp3_db_available()){try{$stmt=vp3_db()->prepare("SELECT * FROM notifications WHERE recipient_type='customer' AND recipient_id=? AND status<>'archived' ORDER BY created_at DESC LIMIT 100");$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();$ready=true;}catch(Throwable){}}$pageTitle='Notifications';require VP3_ROOT.'/includes/account-header.php';?>
<div class="page-head"><div><span class="eyebrow">What needs your attention</span><h1>Notifications</h1></div><?php if($rows):?><form method="post"><?=vp3_csrf_field()?><button class="button small secondary">Mark all read</button></form><?php endif;?></div><?php if(!$ready):?><div class="notice">Notifications become available after the operations migration is imported.</div><?php else:?><div class="notification-list"><?php foreach($rows as $n):?><article class="<?=vp3_e($n['status'])?>"><div><span><?=vp3_e($n['category'])?></span><h3><?=vp3_e($n['title'])?></h3><p><?=vp3_e($n['message'])?></p><small><?=vp3_e($n['created_at'])?></small></div><div><?php if($n['action_url']):?><a class="button small" href="<?=vp3_e(vp3_url($n['action_url']))?>">Open</a><?php endif;?><?php if($n['status']==='unread'):?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="id" value="<?=(int)$n['id']?>"><button class="button small secondary">Mark read</button></form><?php endif;?></div></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><p>You are all caught up.</p></div><?php endif;?></div><?php endif;?>
<?php require VP3_ROOT.'/includes/account-footer.php'; ?>
